    async getAll() { /* SELECT data FROM ${table} ORDER BY ${opts.orderBy || 'created_at'} → rows.map(r => dec(r.data)) */ },
    async getById(id) { /* SELECT data WHERE id = $1 → dec */ },
    async save(doc) { /* upsert with JSON.stringify(enc(doc)) */ },
    async remove(id) { /* DELETE, return rowCount > 0 */ },
  };
}
