export async function readBodyCapped(res: Response, maxBytes: number): Promise<Buffer> {
  const reader = res.body?.getReader();
  if (!reader) {
    const buf = Buffer.from(await res.arrayBuffer());
    if (buf.length > maxBytes) throw new Error(`File too large to read (${(buf.length / 1024 / 1024).toFixed(1)} MB; max ${(maxBytes / 1024 / 1024).toFixed(1)} MB).`);
    return buf;
  }
  const chunks: Uint8Array[] = []; let total = 0;
  for (;;) {
    const { done, value } = await reader.read();
    if (done) break;
    if (!value) continue;
    total += value.length;
    if (total > maxBytes) { try { await reader.cancel(); } catch {} throw new Error(`File too large to read (>${(maxBytes / 1024 / 1024).toFixed(1)} MB).`); }
    chunks.push(value);
  }
  return Buffer.concat(chunks);
}
