const awaitVoiceResult = useCallback(({ callId, resEvent, reqEvent, payload, timeoutMs, matches = () => true, describe, onStart, onSettle }) => {
  const sock = socketRef.current; const agentId = activeAgentIdRef.current;
  if (!sock || !agentId) { sendFunctionOutput(callId, 'Voice session socket is not connected.'); return; }
  onStart?.();
  const pending = { sock, event: resEvent, handler: null, timer: null };
  const settle = () => { clearTimeout(pending.timer); sock.off(resEvent, pending.handler); pendingResultsRef.current.delete(pending); };
  pending.handler = (data) => {
    if (data.agentId !== agentId || !matches(data)) return;
    settle(); onSettle?.(data);
    const text = data.error ? describe.error(data) : data.result || describe.empty;
    setCurrentFunction(data.error ? describe.failed(data) : describe.done);
    addEvent(data.error ? 'error' : describe.eventType, `${describe.label}: ${String(text).slice(0, 200)}`);
    sendFunctionOutput(callId, text);
  };
  pending.timer = setTimeout(() => { settle(); if (activeAgentIdRef.current !== agentId) return; onSettle?.(null); setCurrentFunction(describe.timedOut); addEvent('error', describe.timedOut); sendFunctionOutput(callId, describe.timedOutOutput); }, timeoutMs);
  pendingResultsRef.current.add(pending);
  sock.on(resEvent, pending.handler);
  sock.emit(reqEvent, { agentId, ...payload });
}, [addEvent, sendFunctionOutput]);
// handleDelegation/handleAsk become ~15-line wrappers that set DELEGATING status in onStart and clear it in onSettle; handleManagement passes matches: (d) => d.functionName === functionName.

